INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('A Hundred Memories', 'ဂိုယောင်းရယ် (Kim Da Mi) ဟာ မိသားစုရဲ့ သမီးကြီးပီပီ အိမ်ရဲ့စားဝတ်နေရေးအတွက် ထောက်ပံ့ကူညီပေးရတာကြောင့် ကားမူးတတ်ပေမဲ့လည်း ချောင်းအာသယ်ယူပို့ဆောင်ရေးရဲ့ ဘတ်စ်ကားနံပါတ်၁၀၀မှာ ဘတ်စ်ကားလမ်းညွှန်မလေးအဖြစ် လုပ်ကိုင်နေပြီး တက္ကသိုလ်တက်ရဖို့ အိပ်မက်ရှိသူလည်းဖြစ်ပါတယ်။ ဆောဂျုံဟီး (Shin Ye Eun) ကတော့ ကိုယ့်ကိုယ်ကိုယ်ယုံကြည်မှုရှိပြီး လှပတဲ့ အသစ်ဝင်ရောက်လာတဲ့ ဘတ်စ်ကားလမ်းညွှန်မလေးဖြစ်ပြီး သိပ်မကြာခင်မှာပဲ ဂိုယောင်းရယ်နဲ့ရင်းနှီးပြီး အချစ်ဆုံးသူငယ်ချင်းတွေဖြစ်သွားကြပါတယ်။... (New Series, Seasons: 1, Episodes: 12)', 0, 'series', 'https://m.media-amazon.com/images/M/MV5BZTllMjg0MmYtMmYwNy00MjhhLTgwYzMtNGRmZTcyODYwMGY1XkEyXkFqcGc@._V1_.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Peacemaker S01 + S02', 'Suicide Squad 2 မှာ ပါဝင်ခဲ့တဲ့ ဇာတ်ကောင်တစ်ကောင်ဖြစ်တဲ့ Peacemaker ကြီးရဲ့ စီးရီးသစ်ပါ ဒီစီးရီးကတော့ Suicide Squid 2 မှာ သူ သေနတ်မှန်ပြီး တိုက်ပိပြီးမသေဘဲ ဆေးရုံတက်နေရတာကနေ စပါတယ်၊ ဆေးရုံကဆင်းတဲ့အချိန်မှာ အမန်ဒါဝေါ်လာက သူ့ကို သီးသန့် စစ်ဆင်ရေးတစ်ခုလုပ်ဖို့ အဖွဲ့တစ်ဖွဲ့နဲ့အတူ တာဝန်ပေးလာတဲ့အခါ ဒီစီးရီးဖြစ်လာတာပါ... (Seasons: 2, Episodes: 15)', 8.3, 'series', 'https://image.tmdb.org/t/p/original/yb4F1Oocq8GfQt6iIuAgYEBokhG.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Genie, Make a wish', 'အဘွားဖြစ်သူရဲ့ စောင့်ရှောက်မှုအောက်မှာ တစ်သက်လုံးဖြတ်သန်းလာခဲ့တဲ့ အေးစက်စက်ကောင်မလေး ဂါယောင်း (Bae Suzy) ဟာ တစ်နေ့မှာတော့ မီးခွက်တစ်လုံးကို မထင်မှတ်ဘဲ တက်နင်းမိပြီး နှစ်ထောင်ပေါင်းများစွာက လျှို့ဝှယ်ဆန်းကြယ် ဝိညာဉ်တစ်ခုဖြစ်တဲ့ မီးခွက်စောင့်ဘီလူး ဂျင်နီ(Kim Woo Bin) ကို နှိုးမိသွားခဲ့ကာ ဂျင်နီဆီကနေ ဘဝကို ပြောင်းလဲသွားစေနိုင်တဲ့ ဆုတောင်း ၃ ခု ရရှိခဲ့ပါတယ်။... (Seasons: 1, Episodes: 13)', 6, 'series', 'https://m.media-amazon.com/images/M/MV5BOWM4MjQ1M2EtODY4OS00NGQwLTgxYWYtOTA2ODM3MGU0MTgzXkEyXkFqcGc@._V1_.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Alien: Earth', 'သက္ကရာဇ် ၂၁၂၀ မှာ စတင်ထားပြီး လူသားတွေရဲ့ Ai နဲ့ ခန္ဓာအတုထဲကို အလွှဲအပြောင်းစလုပ်တဲ့ နည်းပညာ သက်တမ်းကြာ အိပ်ပျော်စေတဲ့ ခရိုင်ရိုတောင့်နည်းပညာ စတင်ပေါ်ထွက်လာတဲ့ အချိန်မှာစတင်ထားပါတယ်။ စူပါလူသားအမြန်နှုန်း ခွန်အားတွေပါပြီး မသေနိုင် မအိုမင်းနိုင်တဲ့ SyntheticBody တွေကို မွေးရာပါ ကျန်းမာရေးချို့ယွင်းချက်တွေရှိနေတဲ့ ကလေးတစ်စုနဲ့ စမ်းသပ်ပြီးအောင်မြင်သွားတဲ့လူသားတွေဟာ အာကာသထဲကိုပါ နယ်ချဲ့နေပါပြီ... (Ongoing, Seasons: 1, Episodes: 8)', 0, 'series', 'https://m.media-amazon.com/images/M/MV5BY2RmYmU3NTAtOWU3Ny00YzhmLTljYmItNGQ4NzlkMWE4YTMyXkEyXkFqcGc@._V1_.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Chief of War', '၁၈ ရာစု အဆုံးမှာ ဟာဝိုင်အီကျွန်းစုတွေရဲ့ အဓိက တိုင်းပြည်လေးခုဖြစ်တဲ့ အိုအာဟူ၊ ဘစ်အိုင်းလန်း၊ မာဝီ နဲ့ ခါဝိုင်အီ စစ်ပွဲတွေအကြောင်း အခြေခံထားပါတယ်။ ဇာတ်လိုက်ကတော့ ကာအီရားနာဆိုတဲ့ မာဝီမင်းသားပါပဲ။ ဒီမျိုးနွယ်စုတွေရဲ့ ဟောကိန်းအရ ငှက်မွေးဝတ်ရုံနဲ့ တောက်ပနေတဲ့ကြယ်နဲ့အတူ ထွက်ပေါ်လာတဲ့ ဘုရင်ဟာ တိုင်းပြည်အားလုံးကို စုစည်းပြီး ငြိမ်းချမ်းစေလိမ့်မယ်လို့ပါပါတယ်... (Seasons: 1, Episodes: 9)', 7.6, 'series', 'https://resizing.flixster.com/GD7BOVZeAPtPgtKhhtvkKWxN2ns=/ems.cHJkLWVtcy1hc3NldHMvdHZzZXJpZXMvYzk1NmQ2NWUtMDYyOC00Nzk0LTk1ZWEtYWY1NjYzODdmMjU5LnBuZw==');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Wednesday Season 2', 'ဒီ Season မှာတော့ Wednesday က သူ့အနေနဲ့ Nevermore ကို သိပြီးပြီလို့ထင်ပြီး ကျောင်းကိုသူ့သဘောနဲ့သူပထမဆုံးအကြိမ် ပြန်လာခဲ့တယ်။ သူပြန်ရောက်တော့ Nevermore ကျောင်းက သူထင်ထားသလိုမဟုတ်တော့ဘူး။ သူ့အနေနဲ့နဲ့အရာအားလုံးကိုထိန်းချုပ်နိုင်မယ်ထင် လျှို့ဝှက်ချက်တွေအားလုံးကိုသူသိပြီးပြီထင်ပေမဲ့ သူမသိသေးတဲ့လျှို့ဝှက်ချက်တွေကသူ့ကိုစောင်ကြိုနေခဲ့တယ် ... (Seasons: 2, Episodes: 8)', 8, 'series', 'https://assets.teenvogue.com/photos/6807b02700045157aef67255/master/w_1600%2Cc_limit/491459146_18050962967522143_3181026116073475950_n.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('House of David', 'ဒီဇာတ်လမ်းတွဲလေးကတော့ ၂၀၂၅ မှာ ပူပူနွေးနွေး ထွက်ရှိထားပြီးတော့ ခရစ်ယာန်ကျမ်းစာထဲက အစ္စရေးနဲ့ ဂျူးဒက်က ဒုတိယမျိုးဆက် ရှေးဟောင်းဘုရင်တစ်ပါးဖြစ်တဲ့ ဒေးဗစ်အကြောင်းကို historical fiction အနေနဲ့ ပြန်လည်ရိုက်ကူးတင်ဆက်ထားတာပါ။ (Seasons: 1, Episodes: 8)', 7.4, 'series', 'https://image.tmdb.org/t/p/original/5MhDawWtf7c1FKtlJge48Eix9iC.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Ironheart', 'ဒစ္စနေးက တင်ဆက်လိုက်တဲ့ စီးရီးအသစ်လာပါပြီ။ မာဗယ်စူပါဟီးရိုးဖြစ်ပြီး Black Panther 2 မှာ မိတ်ဆက်ခဲ့ပြီးဖြစ်ပါတယ်။ အိုင်ရန်မန်းရဲ့ ဝတ်စုံကို အတုခိုးပြီး ဝတ်စုံအသစ် တီထွင်လိုက်တဲ့ ဉာဏ်ကြီးရှင် သိပ္ပံပညာရှင်မလေးတစ်ယောက်အကြောင်းပဲဖြစ်ပါတယ်။... (Not yet released, Seasons: 1, Episodes: 6)', 0, 'series', 'https://m.media-amazon.com/images/M/MV5BN2EzMGZhOTktYjVhZi00NmIwLWIxZDEtNWUxZTQyNjhkYWQ4XkEyXkFqcGc@._V1_.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('The Witcher', 'ဝစ်ချာဆိုတာ မှော်ပညာနဲ့ ပြောင်းလဲခံထားရတဲ့လူသားတွေပါ တိုက်ရည်ခိုက်ရည်ကောင်းပြီး အေးစက်စက် လူသားတွေပါပဲ မှော်ပညာ အသေးစားနဲ့ဆေးရည်တွေကိုလည်း အသုံးချနိုင်ပါတယ် အောက်လမ်းနည်းနည်းဆန်လို့ လူတွေမုန်းတီးခံရပါတယ်... (Seasons: 3, Episodes: 24)', 8, 'series', 'https://www.yourdecoration.com/cdn/shop/files/gbeye-fp4983-the-witcher-teaser-poster-61x91-5cm_3ab24575-6ac1-4fd0-b71c-4555cb3fc60f.jpg?v=1721810496');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Game of Thrones', 'ခုနှစ်ပြည်ထောင်တိုင်းရဲ့ ပလ္လင်ကို လုကြမယ့် မျိုးနွယ်စုတွေ…မိသားစုတွေ…. နဂါးတွေ…လူရိုင်းတွေ…လူသန်ကြီးတွေ…မကောင်းဆိုးဝါးတွေ…စတဲ့ မျိုးနွယ်မတူကြသူတွေတိုက်ခိုက်ကြမှာ ဖြစ်ပြီး ကြမ်းကြုတ်ရက်စက်မှုတွေ…..မေတ္တာတရားတွေ…လိမ်လည်လှည့်ဖျားမှုတွေ…ရိုးသားဖြောင့်မတ်သစ္စာစောင့်သိမှုတွေကို တွေ့မြင်ကြရမှာဖြစ်ပါတယ်။ ဇာတ်လမ်းက တကယ့်ကို မထင်မှတ်တာတွေပဲရိုက်ပြထားပြီးသတ်တာဖြတ်တာတွေပီပြင်လွန်းတာကြောင့်... (Seasons: 8, Episodes: 73)', 9.2, 'series', 'https://m.media-amazon.com/images/M/MV5BMTNhMDJmNmYtNDQ5OS00ODdlLWE0ZDAtZTgyYTIwNDY3OTU3XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('The Sandman', 'American Gods တို့ Norse Mythology တို့ကို ရေးခဲ့တဲ့ စာရေးဆရာကြီး နီးလ်ဂိုင်မန်ရဲ့ လက်ရာတွေထဲက Sandman ဆိုတဲ့ နတ်ဘုရား စွမ်းအားရှင် တစ်ယောက်အကြောင်းပါပဲ။ ဇာတ်လမ်းအစမှာတော့ ကမ္ဘာနှစ်ခုကို အရင်ပြသထားပါတယ်။ လူသားတွေ နေတဲ့ နိုးထကမ္ဘာနဲ့ အိပ်မက်ကမ္ဘာပေါ့။ အိပ်မက်ကမ္ဘာရဲ့ နတ်ဘုရားဟာ သူ့ဆီ ကနေ ထွက်ပြေးပြီး လူတွေကို ဒုက္ခပေးနေတဲ့ အိပ်မက်ဆိုးတစ်ကောင်ကို လိုက်ဖမ်းနေခဲ့ပါတယ်။ ဖမ်းမိသွားတဲ့အချိန်လေးမှာပဲ ဘာမှမလုပ်ခင် သူ့ကို လူသားတစ်စုက မှော်အစီအရင်တွေနဲ့ ထောင်ချောက်ဆင်ဖမ်းတာခံလိုက်ရပါတယ်... (Seasons: 2, Episodes: 18)', 7.7, 'series', 'https://comicbook.com/wp-content/uploads/sites/4/2022/07/b87bfa41-24d7-4041-8bbe-e219c41aba52.jpg?w=1024');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Dune: Prophecy', 'ပေါ အထရေးဒီး နန်းမတက်ခင် နှစ် ၁၀,၀၀၀ အလို ကာလမှာပဲ ဖြစ်ပါတယ်။ မဟာစစ်ပွဲကြီးလို့ခေါ်တဲ့ လူသားတွေက ဦးနှောက်ရှိတဲ့စက်တွေထိန်းချုပ်ထားတာကို တော်လှန်ရေးလုပ်ခဲ့တဲ့ ကာလအပြီးပါပဲ။ အဲဒီကာလမှာ စက်တွေကို ကန့်သတ်ပစ်လိုက်ပြီး ကရီနိုအိမ်တော်က ဧကရာဇ်နေရာကို ရယူထားပါတယ်။ အခြား အင်အားကြီးအိမ်တော်ကြီးတွေက နိုင်ငံရေးကစားကွက်မျိုးစုံနဲ့ အားပြိုင်နေတဲ့ ကာလဖြစ်ပါတယ်... (Seasons: 1, Episodes: 8)', 7, 'series', 'https://image.tmdb.org/t/p/original/lmZpYJCjWcCZ6lGF0Vw2Rd8Mmmb.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('WandaVision', 'စီးရီးကိုတော့ sit-com ဟာသ ပုံစံနဲ့ အစပြုထားပါတယ်။ ဝန်ဒါနဲ့ ဗီရှင်တို့ဟာ ပျော်ရွှင်စွာ လက်ထပ်ထားတဲ့ စုံတွဲအဖြစ် တည်ရှိနေကြပါတယ်။ သူတို့တွေ ဘယ်လိုလက်ထပ်ခဲ့တယ် ဘာမှာရောက်နေတယ် ဘယ်ကလာတယ်ဆိုတာကို သူတို့ကိုယ်တိုင်တောင် မမှတ်မိတော့ပါဘူး ... (Seasons: 1, Episodes: 9)', 8.3, 'series', 'https://hips.hearstapps.com/hmg-prod/images/screen-shot-2021-02-02-at-10-04-43-am-1612278326.png');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('The Boys', 'စူပါ ပါဝါရှိပြီး လူတွေကိုအကျိုးပြုနေတဲ့ Hero တွေရှိသလို အနိုင့်ကျင်ပြီး ကိုယ်ကျိုးအတွက် အသုံးချနေတဲ့ သူရဲကောင်းဟန်ဆောင်ထားတဲ့ မိစ္ဆာလိုကောင်တွေလည်းအများကြီးရှိပါတယ်… ဒီလိုကောင်တွေကြောင့် တစ်ချို့သောသူတွေ အများစွာထိခိုက်နေပေမယ့်လည်း Supervillain လိုကောင်တွေဟာ အင်အားကြီးတာရော အဖွဲ့အစည်းတစ်ခုအနေနဲ့ရှိနေတာရော ထောက်ခံနေတဲ့သူတွေများနေတာကြောင့် ဒေါသတွေကိုမြိုသိပ်နေရတဲ့သူတွေအများကြီးရှိပါတယ်… ဒီအထဲမှာမှ ဘဝက သေလည်းမထူးဘူး …ဒီလိုစူပါပါဝါရနေတဲ့ အရူးတွေကို ရသလောက်ပြန်သတ်မယ်ဆိုပြီး The Boys ဆိုတဲ့အဖွဲ့အစည်းလေးပေါ်ပေါက်လာတဲ့အချိန်မှာတော့... (Seasons: 4, Episodes: 32)', 8.7, 'series', 'https://i.redd.it/which-season-of-the-boys-had-the-best-promotional-posters-v0-rdr6y2yymh1a1.jpg?width=1200&format=pjpg&auto=webp&s=984ba6b2add1d85be522588465a3263021e4f02c');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Bad Boy', 'ဒင်း(Dean) ဆိုတဲ့ လူငယ်လေးတစ်ယောက်ဟာ သူ့အမေ ၊ သူညီငယ်လေးတို့နဲ့ အတူနေထိုင်တဲ့ ဆယ်ကျော်သက်လူငယ်လေးတစ်ယောက်ဖြစ်ပါတယ်။တစ်ညမှာတော့ သူအိပ်ဖို့လုပ်နေတုန်း တံခါးခေါက်သံတစ်ခုကြောင့် သူ့ဘဝဟာ ပြောင်းလဲသွားခဲ့ရပါတယ်... (Run time: 1h 55m)', 6.5, 'movie', 'https://m.media-amazon.com/images/M/MV5BYzMxN2FmNDgtYzM5Yy00ZWUzLWJkMDMtZmNjYmI5Mzk1YzBlXkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Loki', 'လိုကီဟာ Endgame မှာတက်ဆာရက်နဲ့အတူ လွတ်မြောက်သွားတာကို အားလုံးအသိပါ။ အခုကတော့လွတ်မြောက်သွားတဲ့လိုကီကို TVA ဆိုတဲ့ စကြဝဠာရဲ့ အချိန်စီးကြောင်းတွေကို စောင့်ရှောက်သူတွေက ဖမ်းဆီးခဲ့ပါတယ်။ သူ့ကို ပြစ်ဒဏ်ချမှတ်ပြီးအချိန်စီးကြောင်းကို ပြန်တည့်မတ်ဖို့ ကြိုးစားခဲ့ပေမယ့် လှည့်စားခြင်းနတ်ဘုရားဆိုတဲ့အတိုင်း TVA ထဲမှာပါပြဿနာတွေ ပေါင်းစုံ ဖြစ်လာတဲ့အခါ... (Seasons: 2, Episodes: 12)', 8.2, 'series', 'https://cdn11.bigcommerce.com/s-ydriczk/images/stencil/1500x1500/products/90302/98771/Loki-season-2-original-tv-one-sheet-poster-buy-now-at-starstills__88779.1698076395.jpg?c=2');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Chernobyl', '၁၉၈၆ ဧပရယ်လမှာ ဆိုဗီယက်ပြည်ထောင်စု၊ ယူကရိန်း နဲ့ ဘီလာရုစ် နယ်မြေကြား ချာနိုဘယ်မှာဖြစ်ခဲ့တဲ့ ကမ္ဘာကျော် အနုမြူဓာတ်အားပေးစက်ရုံ ပေါက်ကွဲမှုအကြောင်း ဖြစ်ရပ်မှန်ကို အခြေခံပြီး တင်ဆင်ထားတာပါ။ အမေရိကန် နဲ့ အားပြိုင်နေချိန်မှာ ဖြစ်ခဲ့တဲ့ အဖြစ်ဆိုးဖြစ်တဲ့အတွက် တရားဝင်ကြေညာတဲ့ အသေအပျောက်စာရင်းဟာ အတော်ကိုလျှော့ပေါ့ထားမယ့်ပုံပေါ်ပါတယ်။ သမိုင်းရဲ့အကြီးဆုံးအနုမြူကပ်ဘေးကို ကျော်လွှားဖို့ ပါဝင်ခဲ့ကြတဲ့ သူရဲကောင်းတွေအကြောင်းကို အဓိက ဇာတ်ကောင် သိပ္ပံပညာရှင်နှစ်ယောက်ကို အခြေတည်ပြီး ရိုက်ကူးပြထားပါတယ်... (Seasons: 1, Episodes: 5)', 9.5, 'series', 'https://m.media-amazon.com/images/M/MV5BNzU0OTI4YTQtNGQ1ZS00ZjA4LTg3MTMtZjkyZWNjN2RiZDJmXkEyXkFqcGc@._V1_.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Wednesday', 'Wednesday ဟာ လူသတ်မှုနဲ့ ကျောင်းကနေ အထုတ်ခံရပြီး သင်းကွဲတွေ လူထူးဆန်းတွေချည်းပဲ တက်တဲ့ နဲဗားမောဆိုတဲ့ကျောင်းကို ရောက်သွားခဲ့ပါ တယ်။ အဲဒီကျောင်းအုပ်ဟာ သူ့ရဲ့အမေနဲ့ ကျောင်းနေဖက်ဖြစ်ခဲ့ပြီး၊ သူ့အမေနဲ့ အဖေကလည်း ဒီကျောင်းမှာပဲ တွေ့ပြီး ချစ်မိခဲ့ကြတာပါ။ အဲဒီကျောင်းမှာ သွေးစုတ်ကောင်တွေ၊ ဝံပုလွေတွေ လို သဘာဝလွန်မျိုးနွယ်တွေ လာစုနေကြတာ ဖြစ်ပါတယ်။ အဲဒီကျောင်းပတ်လည်မှာတော့ ထူးထူးဆန်းဆန်း လူတွေတစစီ လုပ်ပြီး အသတ်ခံရတဲ့အမှုတွေ ဖြစ်နေပါတယ်... (Seasons: 2, Episodes: 9)', 8, 'series', 'https://m.media-amazon.com/images/I/71M8YFEakfL._UF894,1000_QL80_.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('3 Body Problem', 'စကြာဝဠာကြီးထဲမှာ တခြားသက်ရှိတွေများရှိမလားလို့ တွေးမိနေကြတဲ့ လေ့လာသူတွေဟာ တခြားသက်ရှိတွေကို ဆက်သွယ်လို့ ရလိုရငြား အသံထုတ်လွှင့်စက်ကြီးတွေနဲ့ အရင်ကထုတ်လွှင့်နေရာကနေ တရုတ်နိုင်ငံလေ့လာရေးစခန်းတစ်ခုမှာရှိတဲ့ ပညာရှင်တစ်ယောက်က နေရဲ့ ချဲ့ထုတ်နိုင်စွမ်းကိုတွေ့သွားတော့ အားနည်းလှတဲ့ ကမ္ဘာဂြိုလ်က ထုတ်လွှင့်စက်ကို နေဘက်ကိုသာဦးတည်ပြီး လွှင့်လိုက်ရင် ချဲ့ပေးနိုင်မှာပဲဆိုတဲ့ အတွေးနဲ့ သူက ထုတ်လွှင့်ချင်နေတာပါ... (Seasons: 1, Episodes: 8)', 7.6, 'series', 'https://m.media-amazon.com/images/M/MV5BMDdkYWZiZWYtMzA0Yi00NzNlLThkODktY2Q3N2NjN2ExZmMwXkEyXkFqcGc@._V1_.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('Adolescence', 'ဇာတ်လမ်းအစမှာတော့ ဂျေမီဆိုတဲ့ ၁၃ နှစ်အရွယ်ကောင်လေးရဲ့အိမ်ကို ရဲတွေ လက်နက်ကိုင် တပ်ဖွဲ့တွေနဲ့ဝင်စီးနင်းတာကိုတွေ့ရမှာဖြစ်ပြီး သိပ်မကြာခင်မှာပဲ ဂျေမီ့ကို ရဲစခန်းကို ဖမ်းခေါ်သွား ခဲ့ပါတော့တယ်။အဲ့ဒီအခါမှာ မိဘဖြစ်သူတွေကအကျိုးအကြောင်းမေးတဲ့အခါမှာတော့ သူတို့သားကို လူသတ်မှုသံသယရှိသူအနေနဲ့ ဖမ်းဆီးခေါ်ဆောင်သွားတာဖြစ်ကြောင်းသိလိုက်ရပါတော့တယ်... (Seasons: 1, Episodes: 4)', 8.6, 'series', 'https://m.media-amazon.com/images/M/MV5BNGY1YjBiNzMtYWZhNC00OWViLWE0MzItNjc4YzczOGNiM2I0XkEyXkFqcGc@._V1_FMjpg_UX1000_.jpg');
INSERT INTO movies (title, description, rating, type, poster_url) VALUES ('The Last of Us', 'မှိုပိုးတစ်မျိုးကြောင့် လူတွေ အသားစားတဲ့ဇွန်ဘီးတွေလိုဖြစ်သွားပြီး ကမ္ဘာပျက်သွားပြီးနောက် နှစ် ၂၀ မှာအခြေပြုထားပါတယ်။ နယ်မြေတိုင်းမှာ သီးသန့်ဇုံတွေနဲ့ FEDRA အဖွဲ့ကစစ်အာဏာရှင်အဖြစ် တင်းတင်းကြပ်ကြပ်အုပ်ချုပ်နေပါပြီ။ ဇုံတွေထဲက ခိုးထွက်ရင် ခိုးဝင်ရင်ကို ကြိုးပေးသတ်ပါတယ်။ သူတို့တွေကို ပိုးစုန်းကြူးတွေဆိုတဲ့ တော်လှန်ရေးအဖွဲ့တွေကလည်းတိုက်ခိုက်နေပါတယ်... (Seasons: 2, Episodes: 16)', 8.6, 'series', 'https://m.media-amazon.com/images/M/MV5BYWI3ODJlMzktY2U5NC00ZjdlLWE1MGItNWQxZDk3NWNjN2RhXkEyXkFqcGc@._V1_.jpg');
